import React, { useState } from 'react';

const Taskbar = ({ handleMouseEnter, handleMouseLeave, handleClick, taskbarApps }) => {
  const [selectedApp, setSelectedApp] = useState(null);

  const handleAppClick = (app) => {
    if (app === selectedApp) {
      setSelectedApp(null);
    } else {
      setSelectedApp(app);
    }
  };

  return (
    <div className="taskbar taskbar-horizontal">
      {taskbarApps.map((app) => (
        <div
          key={app.id}
          className={`taskbar-app ${app === selectedApp ? 'selected' : ''}`}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
          onClick={() => {
            handleClick(app.name);
            handleAppClick(app);
          }}
        >
          {app.name}
        </div>
      ))}
      {selectedApp && (
        <div className="taskbar-app-text">
          Text content for {selectedApp.name}
        </div>
      )}
    </div>
  );
};

export default Taskbar;
